# Instructions ----
#' This file follows the format generated by FIMS:::use_testthat_template().
#' Necessary tests include input and output (IO) correctness [IO
#' correctness], edge-case handling [Edge handling], and built-in errors and
#' warnings [Error handling]. See `?FIMS:::use_gtest_template` for more
#' information. Every test should have a @description tag that takes up just
#' one line, which will be used in the bookdown report of {testthat} results.


# use_gtest_template ----
## setup ----
# Create temporary files for testing purposes
create_temporary_gtest <- function(temp_path) {
  # Create the directory for the temporary package
  dir.create(temp_path)
  # Save the current working directory and set the new one for the temporary
  # package
  old_wd <- getwd()
  setwd(temp_path)
  # Ensure that the working directory is reset after the function exits
  on.exit(setwd(old_wd), add = TRUE)
  # Create a new package at the specified path
  pkg <- usethis::create_package(temp_path)
  # Set the project to the temporary package directory
  usethis::proj_set(temp_path)
  # Initialize the {testthat} framework for testing
  usethis::use_testthat()
  # Add a folder `gtest` for GoogleTest files
  usethis::use_directory(file.path("tests", "gtest"))
  # Add a `CMakeLists.txt`` file in the `tests/gtest` directory
  cmakelist_path <- file.path("tests", "gtest", "CMakeLists.txt")
  file.create(cmakelist_path)

  # Add a test to the package using the test template

  FIMS:::use_gtest_template(
    class_name = "Selectivity",
    function_name = "Evaluate",
    header_file_path = file.path("inst", "include", "selectivity.hpp"),
    cmakelist_path = cmakelist_path
  )
  # Attempt to use the test template again inside a tryCatch to capture any
  # potential errors
  error <- tryCatch(
    FIMS:::use_gtest_template(
      class_name = "Selectivity",
      function_name = "Evaluate",
      header_file_path = file.path("inst", "include", "selectivity.hpp"),
      cmakelist_path = cmakelist_path
    ),
    error = function(e) {
      # Return a custom error message if an error occurs
      "An error occurred."
    }
  )
  # Return details about the created package, including paths and any errors
  output <- list(
    folder_path = temp_path,
    test_file_path = file.path(
      temp_path, "tests", "gtest", "test_Selectivity_Evaluate.cpp"
    ),
    cmakelist_path = cmakelist_path,
    error = error
  )
}

# Generate temporary files for testing
temp_path <- file.path(tempdir(), "rcmdcheck")
unlink(temp_path, recursive = TRUE, force = TRUE)
output <- create_temporary_gtest(temp_path)
# Ensure the temporary folder is cleaned up after tests are complete
on.exit(unlink(output[["folder_path"]], recursive = TRUE, force = TRUE), add = TRUE)
on.exit(unlink(temp_path))

## IO correctness ----
test_that("use_gtest_template() works with correct inputs", {
  #' @description Test that use_gtest_template() creates the correct test file.
  expect_true(file.exists(output[["test_file_path"]]))

  #' @description Test that use_gtest_template() creates the correct CMake file.
  expect_true(file.exists(file.path(temp_path, output[["cmakelist_path"]])))
})

## Edge handling ----
test_that("use_gtest_template() handles edge cases correctly", {
  #' @description Test that use_gtest_template() throws an error when no input is provided.
  expect_message(
    object = FIMS:::use_gtest_template(
      class_name = "ClassName",
      function_name = "FunctionName",
      header_file_path = "path/to/header.hpp"
    ),
    regexp = "No CMakeLists.txt file provided. Test will not be registered"
  )
})

## Error handling ----
test_that("use_gtest_template() throws an error if the test file already exists", {
  #' @description Test that use_gtest_template() throws an error when the file already exists.
  expect_equal(output[["error"]], "An error occurred.")
})
